const results = $input.first().json.results || [];
const wh = $('Webhook Novo Contato').first().json;
const origin = results.find(t =>
  String(t.id) !== String(wh.ticket_id) &&
  ['open','pending','hold'].includes(t.status) &&
  Array.isArray(t.tags) &&
  t.tags.includes('impulsis_ativo')
);
if (!origin) {
  return [{ json: { found: false, reason: 'origin_not_found', new_ticket_id: wh.ticket_id, requester_id: wh.requester_id } }];
}
return [{ json: {
  found: true,
  new_ticket_id: wh.ticket_id,
  requester_id: wh.requester_id,
  origin_ticket_id: origin.id,
  origin_subject: origin.subject,
  assignee_id_fallback: origin.assignee_id
} }];

const ctx = $('Extrair Ticket Original').first().json;
const comments = $input.first().json.comments || [];

const impulsis_comment = comments.find(c =>
  c.public === false &&
  c.body &&
  c.body.includes('Nome do Template:') &&
  c.body.includes('Destinatario:')
);

let sender_agent_id = null;
let sender_source = 'nao_encontrado';

if (impulsis_comment) {
  sender_agent_id = impulsis_comment.author_id;
  sender_source = 'comentario_impulsis';
}

const assignee_id_final = sender_agent_id || ctx.assignee_id_fallback;
const using_fallback = !sender_agent_id;

return [{ json: {
  found: ctx.found,
  new_ticket_id: ctx.new_ticket_id,
  requester_id: ctx.requester_id,
  origin_ticket_id: ctx.origin_ticket_id,
  origin_subject: ctx.origin_subject,
  assignee_id_final: assignee_id_final,
  assignee_id_fallback: ctx.assignee_id_fallback,
  sender_agent_id: sender_agent_id,
  sender_source: sender_source,
  using_fallback: using_fallback
} }];

const ctx = $('Extrair Agente Disparador do Impulsis').first().json;
const results = $input.first().json.results || [];
const duplicate = results.find(t =>
  String(t.id) !== String(ctx.new_ticket_id) &&
  ['open','pending','hold'].includes(t.status)
);
return [{ json: {
  found: ctx.found,
  new_ticket_id: ctx.new_ticket_id,
  requester_id: ctx.requester_id,
  origin_ticket_id: ctx.origin_ticket_id,
  origin_subject: ctx.origin_subject,
  assignee_id_final: ctx.assignee_id_final,
  assignee_id_fallback: ctx.assignee_id_fallback,
  sender_agent_id: ctx.sender_agent_id,
  sender_source: ctx.sender_source,
  using_fallback: ctx.using_fallback,
  duplicate_child_found: !!duplicate,
  duplicate_child_id: duplicate ? duplicate.id : null
} }];

const agent = $input.first().json.user;
const ctx = $('Validar Duplicidade de Filho').first().json;

const fonte = ctx.using_fallback
  ? 'assignee do ticket original (fallback - comentario Impulsis nao localizado)'
  : 'comentario privado do Impulsis';

const nota = [
  'Retorno Impulsis roteado automaticamente.',
  '',
  'Ticket de origem: #' + ctx.origin_ticket_id + ' (' + ctx.origin_subject + ')',
  'Agente responsavel: ' + agent.name + ' (' + agent.email + ')',
  'Origem do assignee: ' + fonte,
  '',
  'O ticket de origem permanece aberto e sera encerrado automaticamente apos o fechamento deste ticket.'
].join('\n');

return [{ json: {
  new_ticket_id: ctx.new_ticket_id,
  origin_ticket_id: ctx.origin_ticket_id,
  origin_subject: ctx.origin_subject,
  assignee_id_final: ctx.assignee_id_final,
  agent_name: agent.name,
  agent_email: agent.email,
  nota_interna: nota,
  usando_fallback: ctx.using_fallback,
  sender_source: ctx.sender_source
} }];
